/// Helper function to guess the MIME type based on file extension.
/// In a production application, consider using a more robust crate like `mime_guess`.
fn get_mime_type(path: &Path) -> &'static str {
    match path.extension().and_then(|s| s.to_str()) {
        Some("html") => "text/html",
        Some("css") => "text/css",
        Some("js") => "application/javascript",
        Some("json") => "application/json",
        Some("png") => "image/png",
        Some("jpg") | Some("jpeg") => "image/jpeg",
        Some("gif") => "image/gif",
        Some("svg") => "image/svg+xml",
        Some("pdf") => "application/pdf",
        Some("txt") => "text/plain",
        Some("mp3") => "audio/mpeg",
        Some("mp4") => "video/mp4",
        Some("zip") => "application/zip",
        _ => "application/octet-stream", // Default for unknown types
    }
}

/// Actix-web handler to serve files from the "uploads" directory.
/// It takes the filename from the URL path, reads the file, and returns its content.
/// Includes a security check to prevent directory traversal.
async fn serve_upload(filename: web::Path<String>) -> impl Responder {
    let filename_str = filename.into_inner();
    let uploads_base = PathBuf::from("uploads");
    let file_path = uploads_base.join(&filename_str);

    // --- Security Check: Prevent Directory Traversal ---
    // Canonicalize the path to resolve any `..` components or symlinks.
    // This helps ensure the requested file is actually within the intended 'uploads' directory.
    let canonical_file_path = match file_path.canonicalize().await {
        Ok(path) => path,
        Err(e) => {
            if e.kind() == ErrorKind::NotFound {
                return HttpResponse::NotFound().body(format!("File not found: {}", filename_str));
            } else {
                eprintln!("Error canonicalizing path for {}: {:?}", filename_str, e);
                return HttpResponse::InternalServerError().body("Error processing file path");
            }
        }
    };

    // Get the canonical path of the base 'uploads' directory.
    // This `unwrap_or_else` handles the unlikely case where the 'uploads' directory itself
    // cannot be canonicalized, using the original path as a fallback.
    let canonical_uploads_base = uploads_base.canonicalize().await.unwrap_or_else(|e| {
        eprintln!("Warning: Could not canonicalize uploads directory: {:?}", e);
        uploads_base.clone()
    });

    // Ensure the canonicalized file path is a direct child (or descendant) of the 'uploads' directory.
    // If it's not, it's a path traversal attempt or an invalid access.
    if !canonical_file_path.starts_with(&canonical_uploads_base) {
        return HttpResponse::Forbidden().body("Access denied: Path traversal attempt detected.");
    }
    // --- End Security Check ---

    // Attempt to read the file contents asynchronously
    match fs::read(&canonical_file_path).await {
        Ok(contents) => {
            // Determine the MIME type for the Content-Type header
            let mime_type = get_mime_type(&canonical_file_path);
            HttpResponse::Ok()
                .content_type(mime_type)
                .body(contents)
        }
        Err(e) => {
            // Handle file reading errors
            if e.kind() == ErrorKind::NotFound {
                HttpResponse::NotFound().body(format!("File not found: {}", filename_str))
            } else {
                eprintln!("Error reading file {}: {:?}", filename_str, e);
                HttpResponse::InternalServerError().body("Error reading file")
            }
        }
    }
}

